package com.mingalarai import android.view.LayoutInflater import android.view.View import android.view.ViewGroup import android.widget.TextView import androidx.recyclerview.widget.RecyclerView import com.mingalarai.Message class ChatAdapter : RecyclerView.Adapter<ChatAdapter.ViewHolder>() { override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): ViewHolder { val view = LayoutInflater.from(parent.context).inflate(R.layout.chat_item, parent, false) return ViewHolder(view) } override fun onBindViewHolder(holder: ViewHolder, position: Int) { val message = Message() holder.bind(message) } override fun getItemCount(): Int { return 10 } inner class ViewHolder(itemView: View) : RecyclerView.ViewHolder(itemView) { fun bind(message: Message) { val messageTextView: TextView = itemView.findViewById(R.id.messageTextView) messageTextView.text = message.text } } }